-- ═══════════════════════════════════════════════════════════════════════════════
-- smz3.lua — game module for the Archipelago BizHawk connector.
--          SMZ3 — Super Metroid + A Link to the Past Crossover (SNES)
--
-- STATUS: location DETECTION + goal are REAL and SOURCE-DERIVED from the official
-- AP world worlds/smz3 (Client.py = SMZ3SNIClient, Rom.py, __init__.py,
-- TotalSMZ3/Location.py + TotalSMZ3/Item.py + the whole TotalSMZ3/Regions tree).
-- The two 316-entry location tables below (100 Super Metroid + 216 A Link to the
-- Past) were GENERATED by AST-parsing every Location(self, <Id>, <addr>, ...) call
-- in the Regions tree, applying the exact id math the client uses
--   ap_id = locations_start_id(85000) + convertLocSMZ3IDToAPID(Id)
-- (convertLocSMZ3IDToAPID only shifts Id 486..492 down by 34 — visible in LOC_Z3).
-- Mock-verified through MoonSharp against synthetic SRAM ring-queue records.
-- Loads/runs crash-free on any ROM; self-disables on a non-SMZ3 cartridge.
--
-- items_handling = 0b101 (Client.py validate_rom: "local items and remote start
-- inventory"). The PATCHED GAME grants its own locally-found items, so a SOLO seed
-- plays fully and every check is reported in a multiworld. Delivering REMOTE
-- multiworld items is the RECV-ring-queue write path; it is implemented below
-- exactly as Client.py does it, but held behind REMOTE_ITEMS_VERIFIED=false until
-- it can be confirmed in-emulator (a wrong player/item-id encoding could corrupt a
-- save), so receive_item only RECORDS the stream today. Detection + goal are live.
--
-- MEMORY MODEL (SNI → BizHawk)
-- ────────────────────────────
--   The smz3 client is an SNIClient. SNI/FXPAK addresses translate to BizHawk
--   SNES memory domains (same mapping alttp.lua / super_metroid.lua use):
--     SNI WRAM_START(0xF50000)+off → domain "WRAM"    (= $7E0000+off)
--     SNI SRAM_START(0xE00000)+off → domain "CARTRAM" (fallback "SRAM")
--     SNI ROM_START (0x000000)+off → domain "ROM"     (fallback CARTRAM)
--   The multiworld ring queues + cursors live in SRAM; the active-game flag is in
--   SRAM ($E033FE); the Z3 game-mode byte is WRAM $7E0010 and the SM game-mode
--   byte is WRAM $7E0998. The "ZSM" ROM signature is in the ROM header at $00FFC0.
--
-- HOW SMZ3 CHECKS WORK (a SEND ring queue, like Super Metroid — no flag scan)
--   The SMZ3 basepatch maintains a SEND queue in SRAM: the game appends a record
--   per collected location and bumps a write counter; the client advances a read
--   cursor and turns each record's encoded value into a location id. SMZ3 has TWO
--   on-ROM queue layouts ("old" and "new"/optimized); the client picks between
--   them by ROM-name byte 7 (a digit ⇒ new). Both are implemented here exactly as
--   Client.game_watcher does:
--     • record value → item_index:  is_z3 = (hi & 0x80)≠0; masked = is_z3 ? hi&0x7F
--       : hi; item_index = ((lo | (masked<<8)) >> 3) + (256 if is_z3 else 0).
--       That item_index IS the SMZ3-internal location Id (Z3 ids are 256+n), so
--       ap_id = 85000 + convertLocSMZ3IDToAPID(item_index)  →  LOC_SM / LOC_Z3.
--   The RECV queue (client→game, granted items) is the mirror write path — see
--   receive_item (gated).
--
-- GOAL (Client.game_watcher): the active game is read from SRAM $E033FE (byte 0
--   ≠0 ⇒ Super Metroid is running, else A Link to the Past). When the ACTIVE game
--   reaches its endgame mode — SM ∈ {0x26,0x27} (Mother Brain dead / ending) or
--   Z3 ∈ {0x19,0x1A} (credits) — the run is complete (Defeat Ganon + Mother Brain).
--
-- MODULE CONTRACT (called by bizhawk_ap_connector.lua)
--   M.init(ctx) / M.poll() -> {ids} / M.is_goal_complete() -> bool /
--   M.receive_item(item_id, meta)
-- ═══════════════════════════════════════════════════════════════════════════════

local M = {}
M.name = "smz3"

-- Detection + goal are generated from source and mock-verified — LIVE.
local ADDRESSES_VERIFIED = true
-- Remote multiworld item delivery (RECV-queue writes) — implemented, source-
-- derived, but held inert until verified in-emulator. items_handling=0b101 means
-- local items are granted by the patched game regardless, so a solo seed and all
-- check reporting work with this false; only OTHER-player item delivery waits.
local REMOTE_ITEMS_VERIFIED = false

-- ── Memory domains ────────────────────────────────────────────────────────────
local WRAM    = "WRAM"
local CARTRAM = "CARTRAM"     -- SNES battery SRAM in BizHawk; fallback "SRAM"
local ROM     = "ROM"         -- SNES cartridge ROM in BizHawk; fallback CARTRAM

-- ── SNI-space constants, as BizHawk-domain offsets (Client.py module top) ─────
-- WRAM game-mode bytes.
local Z3_GAMEMODE_OFF = 0x0010            -- WRAM: A Link to the Past main module
local SM_GAMEMODE_OFF = 0x0998            -- WRAM: Super Metroid game-state byte

-- ROM header: first 3 bytes of the name field are "ZSM" on an SMZ3 ROM; byte 7
-- (a digit) selects the new/optimized queue layout (Client.validate_rom).
local ROMNAME_OFF     = 0x00FFC0          -- ROM domain
local ROMNAME_SIZE    = 0x15

-- SRAM ring-queue region. Client.py bases everything on SRAM_START + 0x4000.
local QUEUE_BASE      = 0x4000            -- CARTRAM (SRAM): ptr-table + records base
local CURRENTGAME_OFF = 0x33FE            -- CARTRAM: [0]≠0 ⇒ SM active, else Z3

-- Endgame modes per active game (Client.py ENDGAME / SM_ENDGAME).
local Z3_ENDGAME = { [0x19]=true, [0x1A]=true }     -- credits
local SM_ENDGAME = { [0x26]=true, [0x27]=true }     -- Mother Brain dead / ending

-- In-game modes (Client.SMZ3_INGAME_MODES) — used as a poll gate so the
-- title/demo never reports checks. Both games share these mode byte values.
local INGAME_MODES = { [0x07]=true, [0x09]=true, [0x0B]=true }

-- AP base ids (TotalSMZ3/Location.py + Item.py).
local LOCATIONS_START_ID = 85000
local ITEMS_START_ID     = 84000

-- ROM player-name table is bounded; foreign player ids clamp to 0 (Rom.py
-- ROM_PLAYER_LIMIT = 256, used by Client.game_watcher).
local ROM_PLAYER_LIMIT = 256

-- ── Queue layout variants (Client.game_watcher) ───────────────────────────────
-- All offsets are RELATIVE to QUEUE_BASE. send_msg_byte = index of the value
-- byte pair inside an 8-byte (old) / 2-byte (new) SEND record.
local LAYOUT_OLD = {
  send_ptr_off      = 0x680,   -- u16 read cursor (we own) ; +2 = u16 write count
  send_size         = 8,       -- bytes per SEND record
  send_msg_byte     = 4,       -- value lo/hi at record+4 / +5
  send_table_off    = 0x700,   -- SEND records base
  recv_ptr_off      = 0x600,   -- (data[2..3] here = u16 item_out_ptr)
  recv_size         = 4,       -- bytes per RECV record
  recv_table_off    = 0x602,   -- u16 RECV write cursor (we own)
}
local LAYOUT_NEW = {
  send_ptr_off      = 0xD3C,
  send_size         = 2,
  send_msg_byte     = 0,       -- value lo/hi at record+0 / +1
  send_table_off    = 0xDA0,
  recv_ptr_off      = 0xD36,
  recv_size         = 2,
  recv_table_off    = 0xD38,
}

