-- ── Internal state ────────────────────────────────────────────────────────────
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local items_received   = {}     -- ordered stream (extended ITEM lines)
local slot_number      = 0
local layout           = LAYOUT_OLD   -- resolved at ROM check (byte-7 digit ⇒ NEW)
local rom_ok           = nil    -- cached "ZSM" signature result (nil until checked)
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[smz3] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8   = memory.read_u8     or memory.readbyte
  mem.read_u16  = memory.read_u16_le or memory.readword
  mem.write_u8  = memory.write_u8    or memory.writebyte
  mem.write_u16 = memory.write_u16_le or memory.writeword
  return mem.read_u8 ~= nil
end

local function rd(fn, addr, domain)
  if not fn then return nil end
  local ok, v = pcall(fn, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(fn, addr)                       -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function read_wram_u8(off) return rd(mem.read_u8, off, WRAM) end

-- ROM-domain read with a CARTRAM fallback (some cores fold the cart header into
-- CARTRAM; the signature lives in the ROM header either way).
local function read_rom_u8(off)
  local ok, v = pcall(mem.read_u8, off, ROM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, CARTRAM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, "SRAM")
  if ok and type(v) == "number" then return v end
  return nil
end

-- CARTRAM (SRAM) reads/writes with a "SRAM" domain-name fallback.
local function cartram_read_u8(off)
  local ok, v = pcall(mem.read_u8, off, CARTRAM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, "SRAM")
  if ok and type(v) == "number" then return v end
  return nil
end
local function cartram_read_u16(off)
  local lo = cartram_read_u8(off); local hi = cartram_read_u8(off + 1)
  if lo == nil or hi == nil then return nil end
  return lo + hi * 256
end
local function cartram_write_u8(off, value)
  if pcall(mem.write_u8, off, value, CARTRAM) then return true end
  return pcall(mem.write_u8, off, value, "SRAM")
end
local function cartram_write_u16(off, value)
  cartram_write_u8(off, value % 256)
  cartram_write_u8(off + 1, math.floor(value / 256) % 256)
end

local function band(a, b)
  -- bitwise AND without the bit library (cores vary).
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

-- ── ROM identity: the AP basepatch leaves "ZSM" at the ROM-name field, and a
-- digit at byte 7 marks the new/optimized queue layout (Client.validate_rom) ──
local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  local z = read_rom_u8(ROMNAME_OFF)
  local s = read_rom_u8(ROMNAME_OFF + 1)
  local m = read_rom_u8(ROMNAME_OFF + 2)
  if z == nil or s == nil or m == nil then return false end     -- not readable yet
  rom_ok = (z == string.byte("Z") and s == string.byte("S") and m == string.byte("M"))
  if rom_ok then
    -- byte 7 in b"1234567890" ⇒ new message queue (optimized for AP 0.4.4+).
    local b7 = read_rom_u8(ROMNAME_OFF + 7)
    local is_new = b7 ~= nil and ((b7 >= string.byte("1") and b7 <= string.byte("9"))
                                  or b7 == string.byte("0"))
    layout = is_new and LAYOUT_NEW or LAYOUT_OLD
    log(("SMZ3 ROM verified ('ZSM' signature); %s message queue")
        :format(is_new and "new/optimized" or "old"))
  else
    log("non-SMZ3 ROM (no 'ZSM' signature) — detection idle, no writes")
  end
  return rom_ok
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id); if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end   -- no set provided → report all
  return server_locations[ap_id] == true
end

-- Convert a decoded SEND-queue item_index (= smz3 internal location Id, Z3 ids are
-- 256+n) into an AP location id via the generated tables. nil for unknown ids.
local function smz3_index_to_ap(item_index)
  if item_index >= 256 then return LOC_Z3[item_index] end
  return LOC_SM[item_index]
end

-- Item-stream filter, same policy as the other SNES modules: items_handling=0b101
-- means the patched game grants own-world found items itself, so own-world entries
-- are dropped here; server/starting-inventory (player 0, no location) too.
local function accept_item(it)
  if it.player == nil then return true end          -- legacy ITEM:<id> line
  if it.player == 0 and (it.location or 0) <= 0 then return false end
  if it.player == slot_number then return false end -- our own items: game grants them
  return true
end

local function delivery_list()
  local out = {}
  for _, it in ipairs(items_received) do
    if accept_item(it) then out[#out + 1] = it end
  end
  return out
end

-- ── Active-game + gameplay gates ──────────────────────────────────────────────
-- Returns "sm", "z3" or nil. Mirrors Client: SRAM $33FE byte0 ≠0 ⇒ SM.
local function active_game()
  local cg = cartram_read_u8(CURRENTGAME_OFF)
  if cg == nil then return nil end
  return cg ~= 0 and "sm" or "z3"
end

local function game_mode()
  local g = active_game()
  if g == "sm" then return read_wram_u8(SM_GAMEMODE_OFF), g end
  if g == "z3" then return read_wram_u8(Z3_GAMEMODE_OFF), g end
  return nil, nil
end

local function in_gameplay()
  local m = game_mode()
  return m ~= nil and INGAME_MODES[m] == true
end

-- ── Module contract ───────────────────────────────────────────────────────────

function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  slot_number = tonumber(cfg.slot_number) or 0
  load_locations(cfg.locations)

  local n = 0
  for _ in pairs(LOC_SM) do n = n + 1 end
  for _ in pairs(LOC_Z3) do n = n + 1 end
  log(("ready: slot #%d, %d location ids (detection live; remote-item delivery %s)")
      :format(slot_number, n,
              REMOTE_ITEMS_VERIFIED and "live" or "recorded-only (gated)"))
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  if not in_gameplay() then return new end

  -- SEND queue: ptr table at QUEUE_BASE+send_ptr_off holds [read_u16, write_u16].
  local read_idx  = cartram_read_u16(QUEUE_BASE + layout.send_ptr_off)
  local write_cnt = cartram_read_u16(QUEUE_BASE + layout.send_ptr_off + 2)
  if read_idx == nil or write_cnt == nil then return new end

  local guard = 0
  while read_idx < write_cnt and guard < 512 do
    guard = guard + 1
    local rec = QUEUE_BASE + layout.send_table_off + read_idx * layout.send_size
    local lo = cartram_read_u8(rec + layout.send_msg_byte)
    local hi = cartram_read_u8(rec + layout.send_msg_byte + 1)
    if lo == nil or hi == nil then break end

    -- Client.game_watcher decode: Z3 items flag the high bit of the hi byte.
    local is_z3   = band(hi, 0x80) ~= 0
    local masked  = is_z3 and band(hi, 0x7F) or hi
    local item_index = math.floor((lo + masked * 256) / 8) + (is_z3 and 256 or 0)

    local ap_id = smz3_index_to_ap(item_index)
    if ap_id and wanted(ap_id) then new[#new + 1] = ap_id end

    read_idx = read_idx + 1
    cartram_write_u16(QUEUE_BASE + layout.send_ptr_off, read_idx)   -- advance cursor
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  local m, g = game_mode()
  if m == nil then return false end
  if g == "sm" then return SM_ENDGAME[m] == true end
  return Z3_ENDGAME[m] == true
end

-- Record the grant, then (when verified) push pending REMOTE items into the RECV
-- ring and bump the write cursor — the mirror of Client.game_watcher's recv path.
-- Held behind REMOTE_ITEMS_VERIFIED until confirmed in-emulator; until then this
-- only records the stream (own-world items are granted by the patched game).
function M.receive_item(item_id, meta)
  if type(meta) == "table" then
    items_received[#items_received + 1] = {
      item     = tonumber(item_id),
      index    = tonumber(meta.index),
      player   = tonumber(meta.player),
      flags    = tonumber(meta.flags),
      location = tonumber(meta.locId),
    }
  else
    items_received[#items_received + 1] = { item = tonumber(item_id) }
  end

  if not (ADDRESSES_VERIFIED and REMOTE_ITEMS_VERIFIED) then return end
  if not rom_is_ap() or not in_gameplay() then return end

  -- RECV queue (Client.game_watcher): item_out_ptr = u16 at recv_ptr_off+2.
  local out_ptr = cartram_read_u16(QUEUE_BASE + layout.recv_ptr_off + 2)
  if out_ptr == nil then return end

  local list = delivery_list()
  local guard = 0
  while out_ptr < #list and guard < 512 do
    guard = guard + 1
    local it = list[out_ptr + 1]
    if not it or not it.item then break end

    local g_item_id = band((it.item or 0) - ITEMS_START_ID, 0xFFFF)
    local pid = it.player or 0
    if pid >= ROM_PLAYER_LIMIT then pid = 0 end

    local rec = QUEUE_BASE + out_ptr * layout.recv_size
    if layout.recv_size == 2 then
      -- new queue: bytes([player_id, item_id])  (single byte each)
      cartram_write_u8(rec + 0, band(pid, 0xFF))
      cartram_write_u8(rec + 1, band(g_item_id, 0xFF))
    else
      -- old queue: bytes([pid&0xFF, pid>>8, item&0xFF, item>>8])
      cartram_write_u8(rec + 0, band(pid, 0xFF))
      cartram_write_u8(rec + 1, band(math.floor(pid / 256), 0xFF))
      cartram_write_u8(rec + 2, band(g_item_id, 0xFF))
      cartram_write_u8(rec + 3, band(math.floor(g_item_id / 256), 0xFF))
    end

    out_ptr = out_ptr + 1
    cartram_write_u16(QUEUE_BASE + layout.recv_table_off, out_ptr)
  end
end

return M
